      },
      json: true,
    });
  } catch (error) {
    console.log('Welcome message failed: ' + error.message);
  }

  // Notify admin if unknown sender (AC 4)
  if (!senderIdentified) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage',
        body: {
          chat_id: ADMIN_CHAT_ID,
          text: '\u05e2\u05d5\u05d1\u05d3 \u05d7\u05d3\u05e9 \u05d9\u05e6\u05e8 \u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u05d1\u05d5\u05d8:\n\u05e9\u05dd: ' + senderFirstName + '\nTelegram ID: ' + senderTelegramId + '\nUsername: @' + (senderUsername || '\u05dc\u05dc\u05d0'),
        },
        json: true,
      });
    } catch (error) {
      console.log('Admin /start notification failed: ' + error.message);
    }
  }

  // Terminal path — return empty to stop pipeline
  return [];
}

// Not /start — build enriched output for downstream
const outputData = {
  ...items[0].json,
  sender_telegram_id: senderTelegramId,
  sender_telegram_username: senderUsername,
  sender_first_name: senderFirstName,
  sender_language_code: senderLanguageCode,
};

if (senderIdentified) {
  outputData.sender_identified = true;
  outputData.sender_profile_id = senderProfile.id;
  outputData.sender_name = senderProfile.full_name;
  outputData.sender_language_pref = senderProfile.language_pref;
  outputData.sender_role = senderProfile.role;
} else {
  outputData.sender_identified = false;
}

return [{ json: outputData }];

// Onboarding Prompt — sends language-detected onboarding message to unknown worker
// Sends admin notification about unlinked worker
// Passes through original message data (voice notes still processed)
// Story 2-7 Tasks 3, 5

const TELEGRAM_BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';
const ADMIN_CHAT_ID = '1867642206';

const data = items[0].json;
const chatId = data.message.chat.id;
const senderFirstName = data.sender_first_name || '';
const senderTelegramId = data.sender_telegram_id || String(data.message.from.id);
const senderUsername = data.sender_telegram_username || '';
const languageCode = data.sender_language_code || '';

