const promptText = isThaiLanguage
  ? '\u0e2a\u0e27\u0e31\u0e2a\u0e14\u0e35\u0e04\u0e48\u0e30! \ud83d\udc4b \u0e23\u0e30\u0e1a\u0e1a\u0e22\u0e31\u0e07\u0e44\u0e21\u0e48\u0e23\u0e39\u0e49\u0e08\u0e31\u0e01\u0e1a\u0e31\u0e0d\u0e0a\u0e35 Telegram \u0e02\u0e2d\u0e07\u0e04\u0e38\u0e13 \u0e01\u0e23\u0e38\u0e13\u0e32\u0e2a\u0e48\u0e07\u0e0a\u0e37\u0e48\u0e2d\u0e40\u0e15\u0e47\u0e21\u0e02\u0e2d\u0e07\u0e04\u0e38\u0e13\u0e40\u0e1e\u0e37\u0e48\u0e2d\u0e25\u0e07\u0e17\u0e30\u0e40\u0e1a\u0e35\u0e22\u0e19'
  : '\u05e9\u05dc\u05d5\u05dd! \ud83d\udc4b \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05d6\u05d4\u05d4 \u05d0\u05ea \u05de\u05e1\u05e4\u05e8 \u05d4\u05d8\u05dc\u05d2\u05e8\u05dd \u05e9\u05dc\u05da \u05d1\u05de\u05e2\u05e8\u05db\u05ea. \u05d0\u05e0\u05d0 \u05e9\u05dc\u05d7/\u05d9 \u05d0\u05ea \u05e9\u05de\u05da \u05d4\u05de\u05dc\u05d0 \u05db\u05d3\u05d9 \u05e9\u05e0\u05d5\u05db\u05dc \u05dc\u05e7\u05e9\u05e8 \u05d0\u05d5\u05ea\u05da.';

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage',
    body: { chat_id: chatId, text: promptText },
    json: true,
  });
} catch (error) {
  console.log('Onboarding prompt failed: ' + error.message);
}

// Send admin notification about unlinked worker (AC 1, 2)
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage',
    body: {
      chat_id: ADMIN_CHAT_ID,
      text: '\u05e2\u05d5\u05d1\u05d3 \u05dc\u05d0 \u05de\u05d6\u05d5\u05d4\u05d4 \u05e4\u05e0\u05d4 \u05dc\u05d1\u05d5\u05d8:\n\u05e9\u05dd: ' + senderFirstName + '\nTelegram ID: ' + senderTelegramId + '\nUsername: @' + (senderUsername || '\u05dc\u05dc\u05d0') + '\n\ud83d\udd17 \u05d9\u05e9 \u05dc\u05e7\u05e9\u05e8 \u05d0\u05ea \u05d4\u05e2\u05d5\u05d1\u05d3 \u05dc\u05e4\u05e8\u05d5\u05e4\u05d9\u05dc \u05d1\u05de\u05e2\u05e8\u05db\u05ea',
    },
    json: true,
  });
} catch (error) {
  console.log('Admin unlinked-worker notification failed: ' + error.message);
}

// Pass through original message data — voice notes still processed through pipeline
return [{ json: { ...data, onboarding_sent: true } }];

// Clock-In Command Handler (/clockin [area])
// Creates attendance_logs record with status = pending_clockout
// Story 6.1 Tasks 3.1–3.8, Task 5.1–5.2

const { DateTime } = require("luxon");

// Hebrew response constants (Task 5.1)
const CLOCKIN_SUCCESS = "התחלת שיפט ✅ — {{worker}}, {{area}}";
const ERROR_ALREADY_CLOCKED_IN = "יש לך שיפט פתוח — שלח /clockout לסיום";
const ERROR_UNKNOWN_AREA = "שטח לא מזוהה. שטחים זמינים: {{areas}}";
const CLOCKIN_USAGE = "שלח /clockin [שם שטח] — לדוגמה: /clockin אבוקדו";

const SUPABASE_URL = "https://jnsfklshpabogzvolzct.supabase.co";
const SERVICE_KEY = "<SUPABASE_SERVICE_ROLE_KEY>";
const TELEGRAM_BOT_TOKEN = "<TELEGRAM_BOT_TOKEN>";

const headers = {
  "apikey": SERVICE_KEY,
  "Authorization": "Bearer " + SERVICE_KEY,
