};

const message = items[0].json.message;
const chatId = message.chat.id;
const msgTimestamp = message.date;
const jerusalemTime = DateTime.fromSeconds(msgTimestamp, { zone: "Asia/Jerusalem" });
const workDate = jerusalemTime.toFormat("yyyy-MM-dd");
const timestampTz = jerusalemTime.toISO();

// Telegram send helper (arrow fn preserves this)
const send = async (text) => {
  await this.helpers.httpRequest({
    method: "POST",
    url: "https://api.telegram.org/bot" + TELEGRAM_BOT_TOKEN + "/sendMessage",
    body: { chat_id: chatId, text, parse_mode: "HTML" },
