  return [];
}

// Task 3.2: Parse area argument
const areaArg = (message.text || "").trim().replace(/^\/clockin\s*/, "").trim();

if (!areaArg) {
  await send(CLOCKIN_USAGE);
  return [];
}

// Task 3.3: Lookup Area by Alias then by Name
const safeName = areaArg.replace(/%/g, "\\%").replace(/_/g, "\\_");
let areaId = null;
let areaName = null;

try {
  const aliasResp = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/area_aliases",
    qs: { alias: "ilike." + safeName, select: "area_id,areas!inner(id,name)" },
    headers,
    json: true,
  });

  if (aliasResp && aliasResp.length > 0) {
    areaId = aliasResp[0].area_id;
    areaName = aliasResp[0].areas?.name || areaArg;
  } else {
    const areaResp = await this.helpers.httpRequest({
      method: "GET",
      url: SUPABASE_URL + "/rest/v1/areas",
      qs: { name: "ilike." + safeName, is_active: "eq.true", select: "id,name" },
      headers,
      json: true,
    });
    if (areaResp && areaResp.length > 0) {
      areaId = areaResp[0].id;
      areaName = areaResp[0].name;
    }
  }
} catch (err) {
  console.log("Area lookup failed: " + err.message);
}

// Task 3.4: Handle Unknown Area — list available areas
if (!areaId) {
  try {
    const allAreas = await this.helpers.httpRequest({
      method: "GET",
      url: SUPABASE_URL + "/rest/v1/areas",
      qs: { is_active: "eq.true", select: "name", order: "name.asc" },
      headers,
      json: true,
    });
    const areaList = (allAreas || []).map(a => a.name).join(", ");
    await send(ERROR_UNKNOWN_AREA.replace("{{areas}}", areaList));
  } catch (err) {
    await send("שגיאה — נסה שוב");
  }
  return [];
}

// Task 3.5: Check for active clock-in today
try {
  const openResp = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/attendance_logs",
    qs: {
      profile_id: "eq." + profile.id,
      work_date: "eq." + workDate,
      status: "eq.pending_clockout",
      select: "id",
    },
    headers,
    json: true,
  });

  // Task 3.6: Reject duplicate clock-in
  if (openResp && openResp.length > 0) {
    await send(ERROR_ALREADY_CLOCKED_IN);
    return [];
  }
} catch (err) {
  console.log("Active clock-in check failed: " + err.message);
}

// Task 3.7: Insert Attendance Log
try {
  await this.helpers.httpRequest({
    method: "POST",
    url: SUPABASE_URL + "/rest/v1/attendance_logs",
    headers: { ...headers, "Prefer": "return=representation" },
    body: {
      profile_id: profile.id,
      area_id: areaId,
      work_date: workDate,
      start_time: timestampTz,
      status: "pending_clockout",
      source: "bot",
      telegram_message_id: message.message_id,
    },
    json: true,
