} catch (err) {
  console.log("Insert attendance failed: " + err.message);
  await send("שגיאה בשמירת הנתונים — נסה שוב");
  return [];
}

// Task 3.8: Send confirmation
await send(CLOCKIN_SUCCESS.replace("{{worker}}", profile.full_name).replace("{{area}}", areaName));
return [];

// Clock-Out Command Handler (/clockout)
// Updates open attendance_logs record: sets end_time, total_hours, status = pending_approval
// Story 6.1 Tasks 4.1–4.6, Task 5.1–5.2

const { DateTime } = require("luxon");

// Hebrew response constants (Task 5.1)
const CLOCKOUT_SUCCESS = "סיום שיפט ✅ — {{worker}}, {{area}}, {{hours}} שעות";
const ERROR_NO_OPEN_SHIFT = "אין שיפט פתוח — שלח /clockin [שטח] להתחלה";

const SUPABASE_URL = "https://jnsfklshpabogzvolzct.supabase.co";
const SERVICE_KEY = "<SUPABASE_SERVICE_ROLE_KEY>";
const TELEGRAM_BOT_TOKEN = "<TELEGRAM_BOT_TOKEN>";

const headers = {
