    json: true,
  });
  if (resp && resp.length > 0) profile = resp[0];
} catch (err) {
  console.log("Worker lookup failed: " + err.message);
}

if (!profile) {
  await send("שלום! 👋 אני לא מזהה את מספר הטלגרם שלך במערכת. אנא שלח/י את שמך המלא כדי שנוכל לקשר אותך.");
  return [];
}

// Task 4.2: Find open clock-in for today
let openRecord = null;

try {
  const openResp = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/attendance_logs",
    qs: {
      profile_id: "eq." + profile.id,
