  if (openResp && openResp.length > 0) openRecord = openResp[0];
} catch (err) {
  console.log("Open clock-in lookup failed: " + err.message);
}

// Task 4.3: Handle no open clock-in
if (!openRecord) {
  await send(ERROR_NO_OPEN_SHIFT);
  return [];
}

// Task 4.4: Calculate total hours
const startTime = DateTime.fromISO(openRecord.start_time, { zone: "Asia/Jerusalem" });
const endTime = DateTime.fromSeconds(msgTimestamp, { zone: "Asia/Jerusalem" });
const totalHours = endTime.diff(startTime, "hours").hours;
const roundedHours = Math.round(totalHours * 10) / 10;

// Task 4.5: Update Attendance Log
try {
  await this.helpers.httpRequest({
    method: "PATCH",
    url: SUPABASE_URL + "/rest/v1/attendance_logs",
