    .replace("{{worker}}", profile.full_name)
    .replace("{{area}}", areaName)
    .replace("{{hours}}", String(roundedHours))
);
return [];

// Lookup Work Type — match extracted verb/noun to work_type_id
const item = $input.item;
const workTypes = $('Fetch Static Lists').first().json.work_types_raw || [];

const extracted = item.json['סוג_עבודה'];
item.json.work_type_id = null;

if (extracted) {
  const exact = workTypes.find(wt => wt.name_he === extracted);
  if (exact) {
    item.json.work_type_id = exact.id;
  } else {
    const partial = workTypes.find(wt =>
      wt.name_he.includes(extracted) || extracted.includes(wt.name_he)
    );
    if (partial) {
      item.json.work_type_id = partial.id;
    }
  }
}
return item;

// Resolve Client — match extracted client name
const item = $input.item;
const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';
const headers = { 'apikey': SERVICE_KEY, 'Authorization': `Bearer ${SERVICE_KEY}`, 'Content-Type': 'application/json' };

const clientName = item.json['לקוח'];
item.json.pending_client_name = null;

if (clientName) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET', url: `${SUPABASE_URL}/rest/v1/clients`,
      qs: { select: 'id,name', is_active: 'eq.true', is_own_farm: 'eq.false', 'or': `(name.ilike.${clientName},name_en.ilike.${clientName})` },
      headers, json: true
    });
    if (res && res.length > 0) {
      console.log(`Client resolved: ${clientName} -> ${res[0].name}`);
    } else {
      const aliasRes = await this.helpers.httpRequest({
        method: 'GET', url: `${SUPABASE_URL}/rest/v1/client_aliases`,
        qs: { select: 'client_id', 'alias': `ilike.${clientName}` },
        headers, json: true
      });
      if (aliasRes && aliasRes.length > 0) {
        console.log(`Client resolved via alias: ${clientName}`);
      } else {
        item.json.pending_client_name = clientName;
        console.log(`Client unresolved: ${clientName}`);
      }
    }
  } catch (e) {
    item.json.pending_client_name = clientName;
    console.log(`Client lookup error: ${e.message}`);
  }
}
return item;

// Lookup Material — match extracted חומרים name against materials table
// Runs after Resolve Client, before Insert Attendance Log
const items = $input.all();

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';
const headers = {
  'apikey': SERVICE_KEY,
  'Authorization': `Bearer ${SERVICE_KEY}`,
  'Content-Type': 'application/json',
};

const materialsRaw = $('Fetch Static Lists').first().json.materials_raw || [];

for (const item of items) {
  const materialName = (item.json['חומרים'] || '').trim();
  item.json.material_id = null;
  item.json.material_name_raw = materialName || null;

  if (materialName && materialsRaw.length > 0) {
    // Exact match (case-insensitive)
    const exact = materialsRaw.find(m =>
      m.name_he && m.name_he.toLowerCase() === materialName.toLowerCase()
    );
    if (exact) {
      item.json.material_id = exact.id;
    } else {
      // Partial match
      const partial = materialsRaw.find(m =>
        m.name_he && (m.name_he.toLowerCase().includes(materialName.toLowerCase()) ||
                      materialName.toLowerCase().includes(m.name_he.toLowerCase()))
      );
      if (partial) {
        item.json.material_id = partial.id;
        console.log(`Partial material match: "${materialName}" → "${partial.name_he}"`);
      } else {
        console.log(`Material unmatched: "${materialName}"`);
      }
    }
  }
}

return items;

return [
  {
    json: {
      reports: $input.all()
    }
  }
];

