// Lookup Worker Profile in Supabase
// Phase 1: Exact ILIKE match on full_name
// Phase 2: Levenshtein fuzzy fallback if exact match fails
// Escapes ILIKE wildcards (% _) to prevent unintended pattern matching
const workerName = ($input.item.json['שם העובד'] || '').trim();
const safeName = workerName.replace(/%/g, '\\%').replace(/_/g, '\\_');

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';
const headers = {
  'apikey': SERVICE_KEY,
  'Authorization': `Bearer ${SERVICE_KEY}`,
  'Content-Type': 'application/json',
};

let profile_id = null;
let match_type = null;

if (workerName) {
  try {
    // Phase 1: Exact ILIKE match
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/profiles`,
      qs: {
        full_name: `ilike.${safeName}`,
        is_active: 'eq.true',
        select: 'id',
      },
      headers,
      json: true,
    });

    if (response && response.length > 0) {
      profile_id = response[0].id;
      match_type = 'exact';
    }
  } catch (error) {
    console.log(`Worker exact lookup failed for "${workerName}": ${error.message}`);
  }

  // Phase 2: Fuzzy fallback via Levenshtein distance
  if (!profile_id) {
    try {
      const allWorkers = await this.helpers.httpRequest({
        method: 'GET',
        url: `${SUPABASE_URL}/rest/v1/profiles`,
        qs: { is_active: 'eq.true', select: 'id,full_name' },
        headers,
        json: true,
      });

      function levenshtein(a, b) {
        const m = a.length, n = b.length;
        const dp = Array.from({length: m + 1}, () => Array(n + 1).fill(0));
        for (let i = 0; i <= m; i++) dp[i][0] = i;
        for (let j = 0; j <= n; j++) dp[0][j] = j;
        for (let i = 1; i <= m; i++)
          for (let j = 1; j <= n; j++)
            dp[i][j] = a[i-1] === b[j-1]
              ? dp[i-1][j-1]
              : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
        return dp[m][n];
      }

      let bestMatch = null;
      let bestDistance = Infinity;
      // Short names (<=3 chars): max distance 1. Longer: 30% of length.
      const threshold = workerName.length <= 3 ? 1 : Math.floor(workerName.length * 0.3);

      for (const w of (allWorkers || [])) {
        const dist = levenshtein(workerName, w.full_name);
        if (dist < bestDistance && dist <= threshold && dist > 0) {
          bestDistance = dist;
          bestMatch = w;
        }
      }

      if (bestMatch) {
        profile_id = bestMatch.id;
        match_type = 'fuzzy';
        console.log(`Fuzzy matched worker "${workerName}" → "${bestMatch.full_name}" (distance: ${bestDistance})`);
      }
    } catch (error) {
      console.log(`Worker fuzzy lookup failed: ${error.message}`);
    }
  }
}

return {
  json: {
    ...$input.item.json,
    profile_id,
    worker_name_raw: workerName,
    worker_match_type: match_type,
  }
};

// Lookup Area by Alias in Supabase
// Phase 1: Exact ILIKE match on area_aliases.alias, then areas.name
// Phase 2: Levenshtein fuzzy fallback if exact match fails
const areaName = ($input.item.json['איזור עבודה'] || '').trim();
const safeName = areaName.replace(/%/g, '\\%').replace(/_/g, '\\_');

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';
const headers = {
  'apikey': SERVICE_KEY,
  'Authorization': `Bearer ${SERVICE_KEY}`,
  'Content-Type': 'application/json',
};

let area_id = null;
let match_type = null;

if (areaName) {
  try {
    // Phase 1a: Exact match on aliases
    const aliasResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/area_aliases`,
      qs: { alias: `ilike.${safeName}`, select: 'area_id' },
      headers,
      json: true,
    });

    if (aliasResponse && aliasResponse.length > 0) {
      area_id = aliasResponse[0].area_id;
      match_type = 'exact_alias';
    } else {
      // Phase 1b: Exact match on area name
      const areaResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: `${SUPABASE_URL}/rest/v1/areas`,
        qs: { name: `ilike.${safeName}`, is_active: 'eq.true', select: 'id' },
        headers,
        json: true,
      });

      if (areaResponse && areaResponse.length > 0) {
        area_id = areaResponse[0].id;
        match_type = 'exact_name';
      }
    }
  } catch (error) {
    console.log(`Area exact lookup failed for "${areaName}": ${error.message}`);
  }

  // Phase 2: Fuzzy fallback via Levenshtein distance
  if (!area_id) {
    try {
      const [allAliases, allAreas] = await Promise.all([
        this.helpers.httpRequest({
          method: 'GET',
          url: `${SUPABASE_URL}/rest/v1/area_aliases`,
          qs: { select: 'area_id,alias' },
          headers,
          json: true,
        }),
        this.helpers.httpRequest({
          method: 'GET',
          url: `${SUPABASE_URL}/rest/v1/areas`,
          qs: { is_active: 'eq.true', select: 'id,name' },
          headers,
          json: true,
        }),
      ]);

      function levenshtein(a, b) {
        const m = a.length, n = b.length;
        const dp = Array.from({length: m + 1}, () => Array(n + 1).fill(0));
        for (let i = 0; i <= m; i++) dp[i][0] = i;
        for (let j = 0; j <= n; j++) dp[0][j] = j;
        for (let i = 1; i <= m; i++)
          for (let j = 1; j <= n; j++)
            dp[i][j] = a[i-1] === b[j-1]
              ? dp[i-1][j-1]
              : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
        return dp[m][n];
      }

      let bestId = null;
      let bestName = null;
      let bestDistance = Infinity;
      const threshold = areaName.length <= 3 ? 1 : Math.floor(areaName.length * 0.3);

      // Check aliases
      for (const a of (allAliases || [])) {
        const dist = levenshtein(areaName, a.alias);
        if (dist < bestDistance && dist <= threshold && dist > 0) {
          bestDistance = dist;
          bestId = a.area_id;
          bestName = a.alias;
        }
      }
      // Check area names
      for (const a of (allAreas || [])) {
        const dist = levenshtein(areaName, a.name);
        if (dist < bestDistance && dist <= threshold && dist > 0) {
          bestDistance = dist;
          bestId = a.id;
          bestName = a.name;
        }
      }

      if (bestId) {
        area_id = bestId;
        match_type = 'fuzzy';
        console.log(`Fuzzy matched area "${areaName}" → "${bestName}" (distance: ${bestDistance})`);
      }
    } catch (error) {
      console.log(`Area fuzzy lookup failed: ${error.message}`);
    }
  }
}

return {
  json: {
    ...$input.item.json,
    area_id,
    area_name_raw: areaName,
    area_match_type: match_type,
  }
};

// Insert Attendance Log into Supabase — with exponential backoff retry (Story 2-6)
// Dual-write: runs in parallel with Google Sheets append
// All fields come from $input.item.json (via Prepare Data + Lookup nodes)
// Retry: max 3 retries, delays 1s/2s/4s. Only retry on transient errors (5xx, network).

const item = $input.item.json;
const profileId = item.profile_id || null;
const areaId = item.area_id || null;

// Fix: use proper null check — parseFloat(x) || null treats 0 as null
const parsedHours = parseFloat(item['שעות עבודה']);
const totalHours = (!isNaN(parsedHours)) ? parsedHours : null;

// Parse work_date — log if locale string can't be parsed
let workDate = null;
const rawDate = item['תאריך'];
if (rawDate) {
  const d = new Date(rawDate);
  if (!isNaN(d.getTime())) {
    workDate = d.toISOString().split('T')[0];
  } else {
    workDate = new Date().toISOString().split('T')[0];
    console.log('work_date parse failed for "' + rawDate + '", falling back to today');
  }
}

// Telegram fields (passed through pipeline from Prepare Data node)
const telegramMessageId = item.telegram_message_id;
const messageDate = item.message_date;
const startTime = (messageDate != null) ? new Date(messageDate * 1000).toISOString() : null;

// Build INSERT payload
const payload = {
  work_date: workDate,
  total_hours: totalHours,
  status: 'pending',
  source: 'bot',
};
if (profileId) payload.profile_id = profileId;
if (areaId) payload.area_id = areaId;
if (telegramMessageId != null) payload.telegram_message_id = telegramMessageId;
if (startTime != null) payload.start_time = startTime;

// Wire raw_transcript from Whisper output (passed through Prepare Data Set node)
if (item.raw_transcript) payload.raw_transcript = item.raw_transcript;

// Wire voice_ref_url from Supabase Storage upload (Story 2-2)
if (item.voice_ref_url != null) payload.voice_ref_url = item.voice_ref_url;

// Wire dunam_covered from entity extraction
const parsedDunam = parseFloat(item['דונם']);
if (!isNaN(parsedDunam) && parsedDunam > 0) payload.dunam_covered = parsedDunam;

// V2: Wire work_type_id from Lookup Work Type node
if (item.work_type_id) payload.work_type_id = item.work_type_id;

// V2: Wire pending_client_name from Resolve Client node
if (item.pending_client_name) payload.pending_client_name = item.pending_client_name;

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co/rest/v1/attendance_logs';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';

// Always use composite on_conflict (telegram_message_id, profile_id) — Story 2-6 Task 6.3
// The composite unique index prevents multi-worker collision from same voice note.
// For NULL profile_id (unmatched workers), PostgreSQL NULLS DISTINCT means no conflict
// is ever detected — effectively a plain INSERT. This is acceptable because unmatched
// workers go through admin review anyway.
const onConflict = 'telegram_message_id,profile_id';

// Retry configuration: exponential backoff for transient errors only
const MAX_RETRIES = 3;
const BASE_DELAY_MS = 1000; // 1s, 2s, 4s

let lastError = null;
for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '?on_conflict=' + onConflict,
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': 'Bearer ' + SERVICE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation,resolution=merge-duplicates',
      },
      body: payload,
      json: true,
    });

    // Success — return immediately (Task 3.4)
    if (attempt > 0) {
      console.log('Supabase insert succeeded on retry ' + attempt);
    }
    return {
      json: {
        ...item,
        supabase_insert: 'success',
        supabase_record_id: Array.isArray(response) ? response[0]?.id : response?.id,
      }
    };
  } catch (error) {
    lastError = error;

    // Task 3.5: Only retry on transient errors (5xx, network timeout)
    // Do NOT retry on 4xx (constraint violations, bad data) — permanent failures
    const statusCode = error.statusCode || error.httpCode || 0;
    const isTransient = statusCode >= 500 || statusCode === 0; // 0 = network error

    if (!isTransient) {
      // Permanent failure — no retry
      console.log('Supabase insert permanent failure (HTTP ' + statusCode + '): ' + error.message);
      break;
    }

    if (attempt < MAX_RETRIES) {
      const delay = BASE_DELAY_MS * Math.pow(2, attempt); // 1s, 2s, 4s
      console.log('Supabase insert attempt ' + (attempt + 1) + ' failed (HTTP ' + statusCode + '), retrying in ' + delay + 'ms...');
      await new Promise(r => setTimeout(r, delay));
    } else {
      console.log('Supabase insert failed after ' + MAX_RETRIES + ' retries: ' + error.message);
    }
  }
}

// All retries exhausted or permanent failure — return error shape (Task 3.3)
return {
  json: {
    ...item,
    supabase_insert: 'error',
    supabase_error: lastError ? lastError.message : 'Unknown error',
  }
};

// Upload Voice Recording to Supabase Storage
// Uses file_unique_id from Telegram download response as filename
// Storage path: voice-recordings/{year}/{month}/{file_unique_id}.ogg
// NOTE: n8n cloud httpRequest serializes Buffers to JSON — dashboard proxy handles conversion

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';

const result = items[0].json.result || {};
const fileUniqueId = result.file_unique_id;

if (!fileUniqueId) {
  return items.map(item => ({ ...item, json: { ...item.json, voice_ref_url: null } }));
}

const now = new Date();
const year = now.getFullYear().toString();
const month = (now.getMonth() + 1).toString().padStart(2, '0');

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

if (!buffer || buffer.length === 0) {
  return items.map(item => ({ ...item, json: { ...item.json, voice_ref_url: null } }));
}

const storagePath = `${year}/${month}/${fileUniqueId}.ogg`;
let voiceRefUrl = null;

for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const uploadResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/storage/v1/object/voice-recordings/${storagePath}`,
      headers: {
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'audio/ogg',
        'x-upsert': 'true',
      },
      body: buffer,
      returnFullResponse: true,
      json: false,
      encoding: null,
    });

    const statusCode = uploadResp.statusCode || uploadResp.status || 'unknown';
    if (typeof statusCode === 'number' && statusCode >= 400) {
      throw new Error(`Upload returned ${statusCode}: ${JSON.stringify(uploadResp.body).substring(0, 200)}`);
    }

    voiceRefUrl = storagePath;
    break;
  } catch (error) {
    if (attempt < 3) {
      await new Promise(r => setTimeout(r, attempt * 1000));
    }
  }
}

return items.map(item => ({
  ...item,
  json: { ...item.json, voice_ref_url: voiceRefUrl },
}));

// Fetch Static Lists from Supabase
// Queries active workers, areas+aliases, clients+aliases, and work types

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';

const startTime = Date.now();
const headers = { 'apikey': SERVICE_KEY, 'Authorization': `Bearer ${SERVICE_KEY}`, 'Content-Type': 'application/json' };

let workersResponse = [];
let areasResponse = [];
let clientsResponse = [];
let workTypesResponse = [];

try {
  workersResponse = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/profiles`, qs: { select: 'full_name', is_active: 'eq.true' }, headers, json: true });
} catch (error) { console.log(`Fetch workers failed: ${error.message}`); }

try {
  areasResponse = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/areas`, qs: { select: 'name,area_aliases(alias)', is_active: 'eq.true' }, headers, json: true });
} catch (error) { console.log(`Fetch areas failed: ${error.message}`); }

try {
  clientsResponse = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/clients`, qs: { select: 'name,name_en,client_aliases(alias)', is_active: 'eq.true', is_own_farm: 'eq.false' }, headers, json: true });
} catch (error) { console.log(`Fetch clients failed: ${error.message}`); }

try {
  workTypesResponse = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/work_types`, qs: { select: 'id,name_he,name_en', is_active: 'eq.true' }, headers, json: true });
} catch (error) { console.log(`Fetch work types failed: ${error.message}`); }

const elapsed = Date.now() - startTime;

const workerNames = (workersResponse || []).map(w => w.full_name).filter(Boolean);
const workerNamesList = workerNames.join(', ');

const areaEntries = [];
for (const area of (areasResponse || [])) {
  if (area.name) areaEntries.push(area.name);
  if (area.area_aliases && area.area_aliases.length > 0) {
    for (const a of area.area_aliases) {
      if (a.alias && a.alias !== area.name) areaEntries.push(a.alias);
    }
  }
}
const areaNamesAndAliasesList = areaEntries.join(', ');

const clientNamesList = (clientsResponse || [])
  .flatMap(c => [c.name, c.name_en, ...(c.client_aliases || []).map(a => a.alias)])
  .filter(Boolean)
  .join(', ');

const workTypesList = (workTypesResponse || []).map(wt => wt.name_he).join(', ');

let whisperPrompt = `\u05d3\u05d9\u05d5\u05d5\u05d7 \u05e9\u05e2\u05d5\u05ea \u05e2\u05d1\u05d5\u05d3\u05d4 \u05d7\u05e7\u05dc\u05d0\u05d9. \u05e9\u05de\u05d5\u05ea \u05e2\u05d5\u05d1\u05d3\u05d9\u05dd: ${workerNamesList}. \u05e9\u05d8\u05d7\u05d9 \u05e2\u05d1\u05d5\u05d3\u05d4: ${areaNamesAndAliasesList}. \u05dc\u05e7\u05d5\u05d7\u05d5\u05ea: ${clientNamesList}. \u05e1\u05d5\u05d2\u05d9 \u05e2\u05d1\u05d5\u05d3\u05d4: ${workTypesList}.`;
if (whisperPrompt.length > 700) {
  whisperPrompt = whisperPrompt.substring(0, 700).replace(/,[^,]*$/, '.');
}

console.log(`Fetch Static Lists: ${workerNames.length} workers, ${areaEntries.length} areas, ${(clientsResponse||[]).length} clients, ${(workTypesResponse||[]).length} work types in ${elapsed}ms`);

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    whisper_prompt: whisperPrompt,
    worker_names_list: workerNamesList,
    area_names_and_aliases_list: areaNamesAndAliasesList,
    client_names_list: clientNamesList,
    work_types_list: workTypesList,
    work_types_raw: workTypesResponse || [],
    fetch_lists_elapsed_ms: elapsed,
  }
}));

// Aggregate Results — collect all per-item insert results into one confirmation payload
// Runs in runOnceForAllItems mode — receives all items after per-item Insert
// Story 2-6: Added pipeline_failed flag, has_errors flag for error notification routing
const results = [];
let telegramMessageId = null;
let chatId = null;
let successCount = 0;
let failCount = 0;
let hasUnmatched = false;
let hasErrors = false;
let voiceRefUrl = null;
const unmatchedDetails = [];

for (const item of items) {
  const d = item.json;
  telegramMessageId = telegramMessageId || d.telegram_message_id;
  chatId = chatId || d.chat_id;
  if (!voiceRefUrl) voiceRefUrl = d.voice_ref_url || null;

  const workerUnmatched = !d.profile_id;
  const areaUnmatched = !d.area_id;
  if (workerUnmatched || areaUnmatched) hasUnmatched = true;
  if (workerUnmatched) unmatchedDetails.push({ type: 'worker', raw_name: d['שם העובד'] || d.worker_name_raw || 'לא ידוע', record_id: d.supabase_record_id || null });
  if (areaUnmatched) unmatchedDetails.push({ type: 'area', raw_name: d['איזור עבודה'] || 'לא ידוע', record_id: d.supabase_record_id || null });

  if (d.supabase_insert === 'success') {
    successCount++;
    results.push({
      worker: d['שם העובד'] || d.worker_name_raw || 'לא ידוע',
      area: d['איזור עבודה'] || 'לא ידוע',
      hours: d['שעות עבודה'] || '?',
      dunam: d['דונם'] || null,
      date: d['תאריך'] || '',
      workType: d['סוג_עבודה'] || null,
      client: d['לקוח'] || null,
      record_id: d.supabase_record_id,
      workerUnmatched,
      areaUnmatched,
    });
  } else {
    failCount++;
    hasErrors = true;
    results.push({
      worker: d['שם העובד'] || d.worker_name_raw || 'לא ידוע',
      area: d['איזור עבודה'] || 'לא ידוע',
      hours: d['שעות עבודה'] || '?',
      dunam: d['דונם'] || null,
      date: d['תאריך'] || '',
      workType: d['סוג_עבודה'] || null,
      client: d['לקוח'] || null,
      failed: true,
      error: d.supabase_error || 'unknown',
      workerUnmatched,
      areaUnmatched,
    });
  }
}

// Task 4.1: pipeline_failed = ALL items failed (no successful inserts)
const pipelineFailed = successCount === 0;

// Format Hebrew summary lines — include date per AC1
// Mark unmatched worker/area names with ⚠️ so Idan knows matching failed
// Mark failed items with ❌ (Task 4.3: partial failure shows error indicators)
const lines = results.map(r => {
  const datePart = r.date ? ` · ${r.date}` : '';
  const dunamPart = r.dunam ? ` · ${r.dunam} דונם` : '';
  const workTypePart = r.workType ? ` · ${r.workType}` : '';
  const clientPart = r.client ? ` (${r.client})` : '';
  const workerLabel = r.workerUnmatched ? `⚠️ ${r.worker}` : r.worker;
  const areaLabel = r.areaUnmatched ? `⚠️ ${r.area}` : r.area;
  if (r.failed) {
    return `${workerLabel} · ${areaLabel}${workTypePart} · ${r.hours}ש'${dunamPart}${clientPart}${datePart} ❌ שגיאה`;
  }
  return `${workerLabel} · ${areaLabel}${workTypePart} · ${r.hours}ש'${dunamPart}${clientPart}${datePart}`;
});

// Task 4.2: If ALL inserts failed, send specific error message (AC3)
if (pipelineFailed) {
  return [{
    json: {
      chat_id: chatId,
      text: 'שגיאה בשמירת הנתונים — אנא שלח שוב',
      reply_markup: '',
      telegram_message_id: telegramMessageId,
      success_count: 0,
      fail_count: failCount,
      has_unmatched: hasUnmatched,
      has_errors: hasErrors,
      pipeline_failed: true,
      unmatched_details: unmatchedDetails,
      voice_ref_url: voiceRefUrl,
    }
  }];
}

// Task 4.3: Partial or full success — show detailed breakdown
let text = `נרשם:\n${lines.join('\n')}`;
if (hasUnmatched) {
  text += '\n\n⚠️ = לא נמצא ברשימה';
  text += '\nפריט ממתין לאישור של סיגל';
}

// Build inline keyboard with confirm/reject using telegram_message_id as batch key
const replyMarkup = {
  inline_keyboard: [[
    { text: 'כן ✅', callback_data: `confirm:${telegramMessageId}` },
    { text: 'בטל ❌', callback_data: `reject:${telegramMessageId}` }
  ]]
};

return [{
  json: {
    chat_id: chatId,
    text: text,
    reply_markup: JSON.stringify(replyMarkup),
    telegram_message_id: telegramMessageId,
    success_count: successCount,
    fail_count: failCount,
    has_unmatched: hasUnmatched,
    has_errors: hasErrors,
    pipeline_failed: false,
    unmatched_details: unmatchedDetails,
    voice_ref_url: voiceRefUrl,
  }
}];

// Send Confirmation — calls Telegram sendMessage API directly
// to support dynamic inline keyboard markup (n8n Telegram node v1.2
// does not accept raw JSON in replyMarkup).

const TELEGRAM_BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';

const chatId = $input.first().json.chat_id;
const text = $input.first().json.text;
const replyMarkup = $input.first().json.reply_markup; // JSON string or empty

const body = {
  chat_id: chatId,
  text: text,
  parse_mode: 'HTML',
};

// Only attach reply_markup if present (all-fail case sends empty string)
if (replyMarkup) {
  body.reply_markup = replyMarkup;
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: body,
    json: true,
  });

  return [{
    json: {
      ok: response.ok || true,
      message_id: response.result ? response.result.message_id : null,
      chat_id: chatId,
    }
  }];
} catch (error) {
  return [{
    json: {
      ok: false,
      error: error.message,
      chat_id: chatId,
    }
  }];
}

// Handle Callback Query (confirm/reject)
// Parses callback_data, updates attendance_logs status via Supabase PATCH,
// calls answerCallbackQuery, and edits/sends follow-up messages.

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';

const TELEGRAM_BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';

// Parse callback data
const callbackQuery = $input.first().json.callback_query;
if (!callbackQuery || !callbackQuery.data) {
  return [{ json: { error: 'No callback_query data found' } }];
}

const callbackData = callbackQuery.data;  // e.g. "confirm:12345678" or "reject:12345678"
const callbackQueryId = callbackQuery.id;
const chatId = callbackQuery.message.chat.id;
const messageId = callbackQuery.message.message_id;

const parts = callbackData.split(':');
const action = parts[0];  // "confirm" or "reject"
const telegramMessageId = parts[1];  // the original voice note message_id

if (!action || !telegramMessageId) {
  return [{ json: { error: 'Invalid callback_data format', raw: callbackData } }];
}

const newStatus = action === 'confirm' ? 'approved' : 'rejected';

// Step 1: PATCH attendance_logs — update status where telegram_message_id matches AND status is still pending
let patchSuccess = false;
let rowsUpdated = 0;

try {
  const patchResponse = await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/attendance_logs`,
    qs: {
      telegram_message_id: `eq.${telegramMessageId}`,
      status: 'eq.pending',
    },
    headers: {
      'apikey': SERVICE_KEY,
      'Authorization': `Bearer ${SERVICE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation',
    },
    body: { status: newStatus },
    json: true,
  });

  rowsUpdated = Array.isArray(patchResponse) ? patchResponse.length : 0;
  patchSuccess = true;
} catch (error) {
  console.log(`Supabase PATCH failed: ${error.message}`);
  patchSuccess = false;
}

// Step 2: answerCallbackQuery — MUST be called regardless of PATCH result
let answerText = '';
if (!patchSuccess) {
  answerText = 'שגיאה — נסה שוב';
} else if (rowsUpdated === 0) {
  answerText = 'כבר טופל';  // Already processed (double-tap)
} else if (action === 'confirm') {
  answerText = `אושר ✅ (${rowsUpdated})`;
} else {
  answerText = `בוטל ❌ (${rowsUpdated})`;
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/answerCallbackQuery`,
    body: {
      callback_query_id: callbackQueryId,
      text: answerText,
    },
    json: true,
  });
} catch (error) {
  console.log(`answerCallbackQuery failed: ${error.message}`);
}

// Step 3: Edit original message to remove inline keyboard buttons
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/editMessageReplyMarkup`,
    body: {
      chat_id: chatId,
      message_id: messageId,
      reply_markup: JSON.stringify({ inline_keyboard: [] }),
    },
    json: true,
  });
} catch (error) {
  console.log(`editMessageReplyMarkup failed: ${error.message}`);
}

// Step 4: Send persistent follow-up message based on outcome
if (!patchSuccess) {
  // NFR5: persistent error message (toast alone is ephemeral)
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: 'שגיאה בעדכון הרשומות — נסה שוב או עדכן ידנית',
      },
      json: true,
    });
  } catch (error) {
    console.log(`Error follow-up message failed: ${error.message}`);
  }
} else if (action === 'reject' && rowsUpdated > 0) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: 'בוטל ❌ — הרשומות לא יישמרו',
      },
      json: true,
    });
  } catch (error) {
    console.log(`Reject follow-up message failed: ${error.message}`);
  }
}

return [{
  json: {
    action,
    telegram_message_id: telegramMessageId,
    rows_updated: rowsUpdated,
    patch_success: patchSuccess,
    callback_answered: true,
  }
}];

// Notify Admin Pending — send Telegram notification to admin for unmatched records OR errors
// Story 2-6 Task 4.4: fires on has_unmatched OR has_errors (not just unmatched)
// Runs in parallel with Send Confirmation — must not delay or block submitter flow

const TELEGRAM_BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';
const ADMIN_CHAT_ID = '1867642206'; // Jonny (temporary — replace with Sigal's chat_id)

const data = items[0].json;

// Task 4.4: Guard — notification needed if entities unmatched OR inserts failed
if (!data.has_unmatched && !data.has_errors) {
  return [{ json: { notification_sent: false, reason: 'no_issues' } }];
}

const unmatchedDetails = data.unmatched_details || [];
const messageParts = [];

// Unmatched entities section
if (data.has_unmatched && unmatchedDetails.length > 0) {
  const unmatchedLines = unmatchedDetails.map(item => {
    if (item.type === 'worker') {
      return `• שם לא מוכר: "${item.raw_name}"`;
    } else {
      return `• איזור לא מוכר: "${item.raw_name}"`;
    }
  });
  messageParts.push(`רשומה חדשה ממתינה לאישור:\n${unmatchedLines.join('\n')}`);
}

// Error section (Task 4.4: notify admin of permanent failures)
if (data.has_errors) {
  if (data.pipeline_failed) {
    messageParts.push(`❌ כל הרשומות נכשלו בשמירה (telegram_message_id: ${data.telegram_message_id})`);
  } else {
    messageParts.push(`⚠️ ${data.fail_count} רשומות נכשלו בשמירה מתוך ${data.success_count + data.fail_count}`);
  }
}

if (data.voice_ref_url) {
  messageParts.push(`🔊 ${data.voice_ref_url}`);
}

const message = messageParts.join('\n\n');

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: {
      chat_id: ADMIN_CHAT_ID,
      text: message,
    },
    json: true,
  });

  return [{ json: { notification_sent: true, admin_chat_id: ADMIN_CHAT_ID, reason: data.has_errors ? 'errors' : 'unmatched' } }];
} catch (error) {
  // Admin notification failure must NOT crash pipeline or block confirmation
  console.log(`Admin notification failed: ${error.message}`);
