  await send(CLOCKIN_USAGE);
  return [];
}

// Task 3.3: Lookup Area by Alias then by Name
const safeName = areaArg.replace(/%/g, "\\%").replace(/_/g, "\\_");
let areaId = null;
let areaName = null;

try {
  const aliasResp = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/area_aliases",
    qs: { alias: "ilike." + safeName, select: "area_id,areas!inner(id,name)" },
