      qs: { select: 'id,name', is_active: 'eq.true', is_own_farm: 'eq.false', 'or': `(name.ilike.${clientName},name_en.ilike.${clientName})` },
      headers, json: true
    });
    if (res && res.length > 0) {
      console.log(`Client resolved: ${clientName} -> ${res[0].name}`);
    } else {
      const aliasRes = await this.helpers.httpRequest({
        method: 'GET', url: `${SUPABASE_URL}/rest/v1/client_aliases`,
        qs: { select: 'client_id', 'alias': `ilike.${clientName}` },
        headers, json: true
      });
      if (aliasRes && aliasRes.length > 0) {
        console.log(`Client resolved via alias: ${clientName}`);
      } else {
        item.json.pending_client_name = clientName;
        console.log(`Client unresolved: ${clientName}`);
      }
    }
  } catch (e) {
    item.json.pending_client_name = clientName;
    console.log(`Client lookup error: ${e.message}`);
  }
}
return items;
